"""
mkt-original Layer — Exodus chapters 36–38
Run: python3 scripts/zc-original-exodus-36-38-fill.py

Key philological decisions:
- Ch 36: chakham lev (wise-hearted craftsman — the biblical theology of skill as Spirit-gift);
  yeter (surplus/more than enough — the overflow of voluntary generosity, v.5-7);
  q'rashim (frames/boards — acacia overlaid with gold as incarnation typology);
  parokhet (inner veil — the barrier/mediator between the courts and the Most Holy Place);
  material gradation: gold→silver→bronze marks increasing distance from divine presence.
- Ch 37: Bezalel personally makes the ark (wayyaas B'tzal'el) — singular agent for the holiest object;
  kapporeth (mercy seat — from kipper, to atone; LXX hilasterion = Rom 3:25);
  miqqshah (hammered work — from qashah; cherubim and menorah branches hammered as one piece);
  peneihem ish el-achiv (faces each toward his brother — the cherubim's mutual gaze over the mercy seat);
  tahor (pure) — the repeated quality standard for the menorah gold.
- Ch 38: qarnotav (horns of the altar — refuge points + blood application sites);
  beqa la-gulgolet (half-shekel per skull/head — gulgolet = Golgotha; census ransom);
  tzov'ot (serving women who gave their bronze mirrors for the laver — only mention in the Pentateuch);
  n'vuv luchot (hollow, made of boards — the altar's construction to make it portable).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EXODUS_ORIGINAL = {
  "36": {
    "1": "<p><b>Bezalel and Oholiab and every craftsman (kol-chakham) in whom YHWH has put skill and intelligence (chakhmah u'tevunah):</b> The combination chakhmah (wisdom/skill) + tevunah (understanding/discernment, from bin = to discern) is the Solomonic wisdom-pair applied to artisanship. All skilled work has the same divine source as prophetic speech; the Spirit (ruach) who fills Bezalel for craftsmanship (31:3) is the same Spirit that equips prophets. The biblical tradition makes no hierarchy between artistic and prophetic gifts.</p>",
    "2": "<p><b>Moses called (vayyiqra) Bezalel and Oholiab and every craftsman in whose heart (libo) YHWH had put skill:</b> The heart (lev) is the seat of both wisdom and volition in Hebrew anthropology; chakhmah placed in the lev = integrated knowledge that operates through the whole person, not merely intellectual competence. <b>Everyone whose heart (kol asher nasa'o libo) stirred him up to come to do the work:</b> Nasa' lev = the heart being lifted/stirred — voluntary motivation from within, not conscription.</p>",
    "3": "<p><b>They received from Moses all the contribution (kol-hat'rumah) that the people of Israel had brought:</b> T'rumah = a contribution lifted up/offered (from rum, to raise); the term for the freewill offering to YHWH. <b>And they still kept bringing him freewill offerings (n'davah) every morning (baboqer baboqer):</b> N'davah = freewill offering (from nadav, to impel freely; the same root as Nadab); the double baboqer (morning morning) emphasizes daily consistency. The people give without being asked, every single morning.</p>",
    "4": "<p><b>So all the craftsmen who were doing every sort of task on the sanctuary came, each from the task he was doing:</b> The skilled workers interrupt their own construction work to deliver a message to Moses — the supply has exceeded the demand. The redundancy of having workers stop work to report excess work is itself a picture of extravagant generosity.</p>",
    "5": "<p><b>The people bring much more than enough (yeter) for doing the work that YHWH has commanded us to do:</b> Yeter = surplus/excess/remainder (from yatar, to remain after completion); the unusual situation of a building campaign where the contributions must be stopped rather than solicited. This is the only place in the OT where Moses must restrain giving rather than urge it. The yeter is what Paul is invoking in 2 Cor 9:7 and 8 — the overflow from cheerful giving.</p>",
    "6": "<p><b>So Moses commanded, and word was proclaimed throughout the camp, 'Let no man or woman do anything more for the contribution for the sanctuary':</b> The proclamation to stop giving (lo ya'asu od m'lacha l't'rumat haqqodesh) is the most remarkable fundraising announcement in history. The people are told to put their money away. <b>So the people were restrained from bringing:</b> Vayyikale ha'am mehavi = the people were held back from bringing; kalah = to hold back/prevent/contain.</p>",
    "7": "<p><b>For the material they had was sufficient to do all the work, and more (vayyoter):</b> Vayyoter = and it remained over/was surplus; the same yater root. The tabernacle's construction fund had a surplus, not a deficit. The theological contrast with every subsequent Temple project (both require hard fundraising) marks the Sinai generation as uniquely generous — or uniquely obedient to the Spirit's prompting.</p>",
    "8": "<p><b>All the craftsmen among the workmen made the tabernacle (hamishkan) with ten curtains of fine twined linen (shesh moshzar):</b> Mishkan = dwelling/tabernacle (from shakan, to dwell — the root of Shekinah); the first layer of the structure. Shesh moshzar = fine twisted/spun linen (moshzar from shazar, to twist thread); blue (t'khelet), purple (argaman), and scarlet (tola'at shani) — the three colors of the high-priestly garments, the Temple veil, and ultimately the symbolism of royalty, priesthood, and sacrifice. <b>Cherubim skillfully worked (ma'aseh choshev):</b> Choshev = a designer/thinker (from chashav, to think/devise); the highest weaving designation in the tabernacle — designs woven in by a thinking craftsman, not merely embroidered on top.</p>",
    "9": "<p><b>The length of each curtain was twenty-eight cubits:</b> The precise dimensions (28 cubits long × 4 cubits wide) reflect the 'pattern of the mountain' (25:9) — not rounded estimates but exact replication of what Moses saw. The architectural exactness of the construction narrative (chapters 36-40) is the formal proof that Israel built what YHWH commanded; the repetition of the commands in chapters 25-31 followed by the execution in chapters 36-40 is a deliberate structural device showing obedient correspondence.</p>",
    "10": "<p><b>He coupled five curtains to one another, and the other five curtains he coupled to one another:</b> The ten curtains are divided into two sets of five, joined by loops and clasps to form one structure — unity achieved through precise joining, not monolithic construction. The two halves (five + five) become one over the meeting point of the ark.</p>",
    "11": "<p><b>He made loops of blue (lulaaot t'khelet) on the edge of the outermost curtain of the first set:</b> Lulaaot = loops (from lul = a spiral/loop); the t'khelet blue loops on the edges of each set align the two halves precisely. The loop-and-clasp system (50 loops × 50 clasps) is the technical connection mechanism of the tabernacle's first layer.</p>",
    "12": "<p><b>Fifty loops were on the one curtain, and fifty loops were on the edge of the curtain that was in the second set; the loops were opposite one another:</b> The precise alignment of 50 loops to 50 loops — each loop on the first panel directly faces a corresponding loop on the second panel. The architectural care for alignment reflects the larger principle: the tabernacle is a unified structure, not a collection of independent parts.</p>",
    "13": "<p><b>And he made fifty clasps of gold (qarsei zahav) and coupled the curtains one to the other with clasps:</b> Qeres = clasp/hook (a rare term; also used in 26:6); the gold clasps join the two sets of ten curtains into one mishkan. Gold clasps at the center of the structure — the joining point directly over the ark — are the most precious connectors. So the tabernacle became one whole (vayehi hamishkan echad): the unity formula; one mishkan from the joining of two sets.</p>",
    "14": "<p><b>He also made curtains of goats' hair (iz'zim) for a tent (ohel) over the tabernacle:</b> The ohel (tent) is the second layer over the mishkan; iz'zim = goats (plural of ez = goat); the coarser goat-hair fabric forms the working tent that protects the fine linen below. The layered construction (mishkan + ohel + ram skin covering + dugong/seal skin covering) creates concentric protective zones around the divine dwelling — beauty hidden under increasingly utilitarian exteriors.</p>",
    "15": "<p><b>The length of each curtain was thirty cubits and the breadth four cubits:</b> The goat-hair curtains are slightly longer than the linen curtains (30 vs. 28 cubits) so they overhang the sides and back of the structure. The careful calculation of overhang (36:13-14 in the original Sinai instructions) is now executed precisely.</p>",
    "16": "<p><b>He coupled five curtains by themselves and six curtains by themselves:</b> The goat-hair layer has eleven curtains (vs. ten for the linen), divided into groups of five and six. The extra curtain (the sixth in the group) provides the additional length needed for the front overhang that 'folds back' (v.29) over the entrance.</p>",
    "17": "<p><b>He made fifty loops on the edge of the outermost curtain of the one set and fifty loops on the edge of the curtain of the other set:</b> The same loop-and-clasp system as the linen layer, now with bronze clasps instead of gold — the outer layer uses bronze (lesser value), the inner layer gold. The material gradient signals gradations of holiness from periphery to center.</p>",
    "18": "<p><b>And he made fifty clasps of bronze (qarsei n'choshet) to couple the tent together that it might be one whole:</b> N'choshet = bronze/copper — the metal of judgment and durability, used for the outer covering and the court. The tent (ohel) is joined with bronze clasps as the mishkan was joined with gold clasps; same structure, different material level.</p>",
    "19": "<p><b>He made for the tent a covering of tanned rams' skins (oroth eilim m'adammim) and a covering of goatskins (oroth t'chashim) on top:</b> The two outer coverings — tanned red rams' skins and t'chash skins (the exact animal is debated: dugong? badger? dolphin? the t'chash is otherwise unknown; some suggest a type of fine leather) — are purely protective, not decorative. The beauty of the inner linen curtains with their cherubim is invisible from outside; the tabernacle appears from the outside as a tent of rough hides.</p>",
    "20": "<p><b>Then he made the upright frames (q'rashim) for the tabernacle of acacia wood (atzei shittim):</b> Q'rashin (also transliterated q'rashim) = planks or frames — the structural skeleton of the tabernacle; shittim = acacia (the hard, durable desert wood). The q'rashim are overlaid with gold: incorruptible hard wood covered in pure gold — a material description that early Christian interpreters read as the two natures of Christ (the human/wood nature covered by/united with the divine/gold nature), though the primary function is architectural durability and portability.</p>",
    "21": "<p><b>Ten cubits was the length of a frame, and a cubit and a half the breadth of each frame:</b> The precise dimensions of each q'reish; the 10-cubit height determines the wall height of the tabernacle. The measurement system (cubit = roughly 18 inches) gives the tabernacle dimensions: approximately 15 feet high, 45 feet long, 15 feet wide — a modest structure by temple standards, deliberately mobile.</p>",
    "22": "<p><b>Each frame had two tenons (yadot sh'tayim), for fitting together:</b> Yadot = hands/tenons (from yad = hand; the protrusion at the base that fits into the silver socket like a hand fitting into a sleeve); sh'tayim = two. Each frame fits into two silver bases, giving it a double-footed stability. The yad-vocabulary for structural joints continues the body-metaphor throughout Exodus's architectural vocabulary.</p>",
    "23": "<p><b>He made twenty frames (q'rashim) for the south side of the tabernacle:</b> Twenty frames × 1.5 cubits each = 30 cubits of wall length on the south side — the total southern wall. The systematic enumeration of every frame and socket through vv.23-30 reflects the legal precision of the construction account: what was commanded is now documented as executed.</p>",
    "24": "<p><b>And forty bases of silver (adnei-kesef) he made under the twenty frames, two bases under one frame for its two tenons:</b> Adon = base/socket/pedestal (from adon = lord? or from the root for foundation?); adnei-kesef = silver bases. Each frame sits in two silver sockets (one per tenon); 20 frames × 2 sockets = 40 silver bases on the south side. The silver bases are made from the census silver (38:27) — the poll-tax half-shekel from every Israelite man. Every Israelite's ransom payment becomes a part of the foundation on which the dwelling of YHWH rests.</p>",
    "25": "<p><b>For the second side of the tabernacle, on the north side, he made twenty frames:</b> The north wall mirrors the south wall — same number of frames, same silver base count. The architectural symmetry of the tabernacle reflects the divine character: ordered, consistent, precise. The repetition of dimensions is not literary padding but the language of covenant faithfulness — what was promised is what was built.</p>",
    "26": "<p><b>And their forty bases of silver: two bases under each frame:</b> The north wall's 40 silver bases = the south wall's 40 bases; total for both long walls = 80 silver bases. The structural foundation of the tabernacle rests on 100 silver talent-worth of bases (38:27): 96 for the walls + 4 for the veil pillars. Each talent of silver = the ransom price for 3,000 men (at a half-shekel each) = the entire 603,550-man census covered.</p>",
    "27": "<p><b>For the rear of the tabernacle westward he made six frames:</b> The western (rear) wall uses six regular frames plus two corner frames (vv.27-28); the rear wall is 9 cubits wide (6 × 1.5), plus the doubled corner posts that close the structure. The tabernacle faces east (the entrance faces east, toward the rising sun and the camp), and its rear faces west — the Most Holy Place is in the western end.</p>",
    "28": "<p><b>He made two frames for corners of the tabernacle in the rear:</b> The corner frames (mikzoa = corners, from qatza = to cut off/corner) are the structural joints that close the rectangular structure. The doubled construction ('coupled beneath and together at the top to the first ring') creates a boxed corner — the corner posts are paired to ensure the frame holds its shape under the weight of the coverings.</p>",
    "29": "<p><b>And they were separate beneath but joined at the top, at the first ring:</b> The corner frames are distinct at the base but converge at the top ring — the unity at the top despite structural separation at the base. The ring (ta'ba'at) at the top is the structural linchpin that ties the wall panels into a continuous perimeter.</p>",
    "30": "<p><b>Thus there were eight frames with their bases of silver: sixteen bases, under every frame two bases:</b> The complete western wall: 8 frames (6 regular + 2 corner) × 2 silver bases = 16 silver bases. Total silver bases: 40 (south) + 40 (north) + 16 (west) = 96, plus 4 for the inner veil pillars = 100 silver bases = 100 silver talents (one talent per base, 38:27).</p>",
    "31": "<p><b>He made bars (b'richim) of acacia wood, five for the frames of the one side of the tabernacle:</b> B'richim = crossbars/bars (from barach = to flee/pass through; the bars pass through rings on the frames, running horizontally through the walls). Five bars per side × 3 sides = 15 bars total. The bars tie the frames together horizontally, preventing lateral movement; the vertical frames + horizontal bars create a rigid grid.</p>",
    "32": "<p><b>And five bars for the frames of the other side of the tabernacle, and five bars for the frames of the tabernacle at the rear westward:</b> The bar system on all three sides: south (5) + north (5) + west (5) = 15 bars of acacia wood, all overlaid with gold. The horizontal bars give the tabernacle its structural rigidity — without them the vertical frames could splay outward under load.</p>",
    "33": "<p><b>And he made the middle bar (hab'riach hattichon) to run from end to end halfway up the frames:</b> The middle bar (tichon = middle/central, from the root for middle) is the key structural element — a single long bar running the entire length of each side, mid-height. The two outer bars run only half the length; the central bar is the structural spine. The assembly of the tabernacle in the field required precise coordination of frames and bars — a sophisticated engineering operation for a portable structure.</p>",
    "34": "<p><b>He overlaid the frames with gold and made their rings of gold for holders for the bars and overlaid the bars with gold:</b> The acacia frames and bars are all gold-overlaid; even the structural members visible only within the frame assembly are covered with gold. There are no hidden corners in YHWH's dwelling — the holiness requirement extends to the invisible structural elements as much as the visible furnishings. The rings (ta'ba'ot) through which the bars pass are also gold.</p>",
    "35": "<p><b>He made the veil (parokhet) of blue and purple and scarlet yarns and fine twined linen; he made it with cherubim skillfully worked (ma'aseh choshev):</b> The parokhet = the inner veil (from a root meaning to divide/separate — it divides the Holy Place from the Most Holy Place). The same three colors as the outer curtains plus fine linen; cherubim woven in (not embroidered — ma'aseh choshev indicates woven designs). This is the curtain torn in two at Jesus's death (Matt 27:51) — the barrier to the divine presence removed by the torn flesh of the High Priest.</p>",
    "36": "<p><b>And he made for it four pillars of acacia and overlaid them with gold. Their hooks were of gold, and he cast for them four bases of silver:</b> The parokhet hangs on four pillars (four = a stable enclosure number), with gold hooks and silver bases. The four silver bases (adnei-kesef) account for four of the 100 silver talent-bases; the inner veil's silver bases are the same material as the wall foundations — the entire inner structure stands on the ransom-silver of the people.</p>",
    "37": "<p><b>He also made a screen (masach) for the entrance of the tent, of blue and purple and scarlet yarns and fine twined linen, embroidered with needlework (ma'aseh roqem):</b> Masach = screen/curtain for the entrance (the outer, accessible curtain — less sacred than the parokhet); ma'aseh roqem = embroidered work (roqem = embroiderer, from raqam = to stitch/embroider in patterns) — a less prestigious weaving technique than the ma'aseh choshev of the inner veil; the entrance screen is embroidered, the inner veil is woven. The gradation of craft level matches the gradation of holiness.</p>",
    "38": "<p><b>And its five pillars with their hooks. He overlaid their capitals (rasheichem) and their fillets (vav = connecting band/hooks) with gold, but their five bases were of bronze (n'choshet):</b> The entrance screen has five pillars (vs. four for the inner veil) with bronze bases (vs. silver). Bronze = the material of judgment and the outer court; silver = the material of the inner zones. The gradient entrance→holy place→most holy place is marked by bronze→silver→gold bases. Rasheichem = their tops/capitals (from rosh = head); vav = a hook or connection-band (also the Hebrew letter vav, which is shaped like a hook).</p>"
  },
  "37": {
    "1": "<p><b>Bezalel made the ark (aron) of acacia wood:</b> The shift from plural construction agents (wayyaasu = they made, in ch.36) to singular (wayyaas B'tzal'el = Bezalel made) for the ark is deliberate. Bezalel personally constructs the holiest object of the tabernacle. The aron (from the same root as the Egyptian sarcophagus box) is the throne-base of YHWH — the dwelling of the Name. The ark's acacia-and-gold construction follows the q'rashin principle: imperishable wood covered in pure gold.</p>",
    "2": "<p><b>He overlaid it with pure gold (zahav tahor) inside and outside, and made a molding of gold around it:</b> Zahav tahor = pure gold (tahor = pure/clean — the ritual cleanness term applied to metal quality); inside and outside (mibayit umichutz) — both surfaces overlaid. The gold molding (zer zahav = golden wreath/crown around the top) may symbolize the divine crown-presence that rests on the ark. The ark is completely enclosed in gold — no wood visible; the divine presence is clothed entirely in purity.</p>",
    "3": "<p><b>And he cast for it four rings of gold for its four feet, two rings on its one side and two rings on its other side:</b> The four gold rings at the four feet (or lower corners — the exact position is debated) are the permanent housing for the poles. The ark's transportation system is built into its design — it was never meant to be stationary. The portable ark (carried on Levitical shoulders, never touched by hands) is the mobile throne of the divine King who travels with his people.</p>",
    "4": "<p><b>He made poles (badim) of acacia wood and overlaid them with gold:</b> Badim = poles (singular bad = separation/isolation — a pole that separates the bearers from the ark); the gold-covered acacia poles are the means of carrying the holiest object in Israel. The poles must never be removed (25:15 — 'The poles shall remain in the rings of the ark; they shall not be taken from it') because the ark is always ready to move, always in a state of divine readiness to journey.</p>",
    "5": "<p><b>And he put the poles into the rings on the sides of the ark to carry the ark:</b> The final assembly of the ark — poles inserted through the rings, the ark itself completed. The ark will not be used until the tabernacle is erected (40:20); until then it stands ready, poles in place, waiting for the dwelling to be built around it.</p>",
    "6": "<p><b>He made a mercy seat (kapporeth) of pure gold:</b> Kapporeth = the mercy seat (from kipper = to atone/cover; the word also appears in 25:17-22). Paul uses the LXX hilasterion (= kapporeth) for Christ in Romans 3:25 — Jesus is the kapporeth, the place where atoning blood is applied and where divine wrath and divine mercy intersect. <b>Two and a half cubits was its length, and one and a half cubits its breadth:</b> The kapporeth exactly covers the ark (same dimensions as the ark's lid), and the cherubim are hammered from the same piece of gold as the kapporeth.</p>",
    "7": "<p><b>And he made two cherubim of gold (k'ruvei zahav). He made them of hammered work (miqqshah) on the two ends of the mercy seat:</b> Miqqshah = hammered/beaten work (from qashah = hard/difficult to work; the same root used for Pharaoh's hardened heart — the material is worked with difficulty, requiring skill and sustained force). The cherubim are not cast separately and attached; they are hammered out of the same piece of gold as the kapporeth — one continuous piece. The organic unity of the cherubim with the mercy seat reflects the inseparability of the guardians of YHWH's presence from the presence itself.</p>",
    "8": "<p><b>One cherub on the one end and one cherub on the other end. Of one piece (miqqshah) with the mercy seat he made the cherubim on its two ends:</b> The emphasis on one piece (miqqshah echad, lit. one hammered work) is repeated from v.7. The artistic and theological point: the kapporeth and its cherubim are not assembled from parts but formed as an integral whole. The artisan who could hammer a cherub and a flat cover from a single gold ingot was demonstrating extraordinary skill — the finest metalwork in the tabernacle.</p>",
    "9": "<p><b>The cherubim spread out their wings above, overshadowing the mercy seat (s'khakhim b'khnapheim al-hakkapporeth) with their wings, with their faces one to another (peneihem ish el-achiv); toward the mercy seat were the faces of the cherubim:</b> Sakhakh = to overshadow/cover (from the same root as sukkah = booth/shelter; the cherubim provide protective covering for the ark). Peneihem ish el-achiv = each facing his brother — the mutual gaze of the cherubim over the mercy seat; they do not look outward at observers but inward at the locus of atonement. Between them and beneath their gaze, YHWH promises to speak (25:22 — 'I will speak with you from above the mercy seat, from between the two cherubim'). The John 20:12 angels at the tomb echo this arrangement.</p>",
    "10": "<p><b>He also made the table (shulchan) of acacia wood:</b> Shulchan = table (the word also used for the royal table at a feast; cf. Ps 23:5 — 'You prepare a table before me'); the table of the Presence (Bread) stands in the Holy Place on the north side. The table-in-the-divine-house continues the royal throne-room imagery of the tabernacle — the ark (throne), the incense altar (before the throne), and the table (the king's banquet provision) map onto a royal court.</p>",
    "11": "<p><b>He overlaid it with pure gold and made a molding of gold around it:</b> The table, like the ark and the incense altar, has a golden molding (zer zahav = golden wreath/crown); the three innermost pieces of furniture all have this crown-molding. The molding may represent a royal coronet — the furniture of the divine court is crowned.</p>",
    "12": "<p><b>He also made a frame (misgeret) around it a handbreadth wide, and a molding of gold around the frame:</b> Misgeret = frame/border/rim (from sagar = to close/shut); the handbreadth (tefach) rim prevents the showbread and its vessels from sliding off. The double molding (one on the table, one on the rim) multiplies the royal crown imagery.</p>",
    "13": "<p><b>He cast for it four rings of gold and fastened the rings to the four corners at its four legs:</b> The table, like the ark, has four gold rings for carrying poles; it is designed for transit. Even the table of the divine Presence travels with Israel — the banquet provision follows the pilgrim people.</p>",
    "14": "<p><b>Close to the frame were the rings, as holders for the poles to carry the table:</b> The rings are positioned close to the frame (the lateral edge) rather than at the feet — this positions the carrying poles outside the table legs, making it easier for the bearers to walk without tripping on the legs.</p>",
    "15": "<p><b>And he made the poles of acacia wood to carry the table, and overlaid them with gold:</b> The table's acacia-and-gold poles mirror the ark's poles in construction. All carrying implements follow the same material protocol as the object they carry: the holiness of the object extends to its transportation apparatus.</p>",
    "16": "<p><b>And he made the vessels of pure gold that were to be on the table, its plates (q'arot) and dishes (kappot) and bowls (q'sayyot) and flagons (m'naqqiyot) with which to pour drink offerings:</b> The complete service set for the table of the Presence: q'arot = flat plates (for the twelve loaves); kappot = hands/pans (perhaps for incense placed alongside the bread); q'sayyot = bowls (for the frankincense? Lev 24:7); m'naqqiyot = flagons (for the drink offerings — liquid libations). All of pure gold (tahor); the vessels are as holy as the table itself.</p>",
    "17": "<p><b>He also made the lampstand (menorah) of pure gold (tahor). He made the lampstand of hammered work (miqqshah):</b> The menorah receives the same material quality standard (tahor = pure/clean gold) and construction method (miqqshah = hammered) as the cherubim and mercy seat — the three most technically demanding pieces of the tabernacle. The menorah is one continuous hammered piece (no joints or welds), requiring the goldsmith to hammer the entire structure including its branches from a single gold ingot. <b>Its base (yarekhah), its shaft (qaneh), its cups (gevi'im), its calyxes (kaptorim), and its flowers (perachim) were of one piece with it (miqqshah hayetah kullah):</b> Yarekhah = thigh/base; qaneh = stalk/reed; gevi'im = cups; kaptorim = knobs/calyxes (from Caphtor, the Aegean origin of the design?); perachim = blossoms/flowers. The botanical vocabulary (cups, calyxes, flowers) is the vocabulary of the almond tree (shaqed).</p>",
    "18": "<p><b>And there were six branches going out of its sides, three branches of the lampstand out of one side of it and three branches of the lampstand out of the other side of it:</b> The seven-branched menorah: one central shaft (qaneh) + six branches (shnei q'nei menorah = six branches of the lampstand) = seven lights total. Seven = the complete week, the Sabbath number. The menorah provides the only light in the Holy Place (there are no windows); its seven lights illuminate the space where priests minister before YHWH.</p>",
    "19": "<p><b>Three cups made like almond blossoms (meshukadim), each with calyx and flower, on one branch, and three cups made like almond blossoms, each with calyx and flower, on the other branch:</b> Meshukadim = shaped like almonds/almond blossoms (from shaqed = almond; the same root gives the verb shakad = to watch/be alert — used in Jer 1:11-12, 'I see an almond branch... for I am watching/shakad over my word to perform it'; the almond is the early-bloomer, the watcher-tree). Three cups per branch = the flowering sequence: calyx (kaptor = bud), petal (perach = flower), open cup (gavia' = cup). The menorah is an almond tree in gold, always in full bloom.</p>",
    "20": "<p><b>And on the lampstand itself were four cups made like almond blossoms, with their calyxes and flowers:</b> The central shaft has four almond cups (vs. three on each branch), making the central shaft the most elaborately flowering element. Total cups: (3 × 6 branches) + (4 × central shaft) = 22 cups of almond-blossom design.</p>",
    "21": "<p><b>And there was a calyx of one piece with it under each pair of the six branches of it:</b> At the junction of each pair of branches where they emerge from the central shaft, there is a knob/calyx of one piece — structural reinforcement at the branching points. The junctions are where fracture would most likely occur in a hammered piece; the calyx both strengthens and beautifies the branching points.</p>",
    "22": "<p><b>Their calyxes and their branches were of one piece with it (miqqshah echad). The whole of it was a single hammered piece (miqqshah echad) of pure gold:</b> The most emphatic restatement of the menorah's unity: miqqshah echad (one hammered piece) stated twice in this verse. The entire menorah — base, shaft, branches, cups, calyxes, flowers — is one continuous piece of worked gold. This is the material embodiment of the 'one' that runs through the tabernacle construction: the mishkan is one (36:13), the mercy seat and cherubim are one piece (37:8), the menorah is one piece.</p>",
    "23": "<p><b>He made its seven lamps (neroteha) and its tongs (malqacheim) and its trays (machtoteha) of pure gold:</b> Nerot = lamps (from ner = lamp/light); malqachayim = tongs/snuffers (for trimming the wicks); machtot = fire-pans/trays (for catching the trimmed wicks and ash). The maintenance tools are as pure as the menorah itself — the instruments of daily service share the holiness standard of the object they service.</p>",
    "24": "<p><b>He made it and all its utensils of a talent (kikkar) of pure gold:</b> Kikkar = a talent (the largest unit of weight; approximately 75 pounds/34 kg of gold). The menorah required one full talent of gold — the largest single-piece gold object in the tabernacle. The investment of an entire talent of gold in a single hammered lamp is a statement: illuminating the presence of YHWH is worth the most precious material available.</p>",
    "25": "<p><b>He made the altar of incense (mizbeach hamiqtar qetoret) of acacia wood:</b> Miqtar = a place of burning/smoking (from qatar = to make smoke); qetoret = incense/smoke-offering. The incense altar (also called mizbeach ha-zahav, the gold altar) is the fourth piece of furniture in the Holy Place, positioned directly before the parokhet. It is the last object encountered before the Most Holy Place — the piece of furniture that mediates between the priest's ministry in the Holy Place and the divine presence beyond the veil.</p>",
    "26": "<p><b>He overlaid it with pure gold, its top (gago), its sides (kirotav), and its horns (qanotav), and made a molding of gold around it:</b> Gag = roof/top (also the word for a house roof); the golden crown-molding (zer) around the incense altar matches the ark and the table, marking it as one of the three furniture pieces requiring the crown. <b>Its horns (qanotav):</b> The incense altar has four horns like the burnt-offering altar, but smaller and of gold rather than bronze. Blood of atonement (on the Day of Atonement and other occasions) is applied to the horns of the incense altar, linking it structurally to the blood atonement system despite its primary incense function.</p>",
    "27": "<p><b>And he made two rings of gold for it under its molding, on two opposite sides of it, as holders for the poles to carry it:</b> The incense altar has two rings (not four like the ark and table), one on each of its two sides. The smaller number of rings for a smaller piece — the incense altar is proportionally smaller than the table and ark (1 cubit × 1 cubit × 2 cubits high, vs. the ark's 2.5 × 1.5 × 1.5 cubits).</p>",
    "28": "<p><b>And he made the poles of acacia wood and overlaid them with gold:</b> Same construction protocol as all other poles: acacia + gold overlay. The incense altar's poles, like all carrying implements, share the material dignity of the object they carry.</p>",
    "29": "<p><b>He made the holy anointing oil also, and the pure fragrant incense (q'toret sammim), blended as by a perfumer (ma'aseh roqeach):</b> The chapter concludes with the two substances (oil and incense) that serve as sensory mediators of divine presence. Shemen mishchat-qodesh = holy anointing oil (used to consecrate every piece of furniture and every priest — the physical transfer of holy status through oil contact). Q'toret sammim = fragrant incense (the specific compound formula of Exod 30:34-38); ma'aseh roqeach = the work of a perfumer (from raqach = to compound/spice) — the same technical designation as the embroiderer and the jeweler; sacred manufacture requires professional expertise.</p>"
  },
  "38": {
    "1": "<p><b>He made the altar of burnt offering (mizbeach ha-olah) of acacia wood:</b> Mizbeach ha-olah = the altar of the whole burnt offering (olah = that which goes up; the completely-consumed sacrifice). This altar is the first object encountered after passing through the court entrance — before the Holy Place, before the laver, the worshipper passes the altar of sacrifice. Access to the divine presence begins with blood. The altar's position at the entry is the spatial theology of atonement.</p>",
    "2": "<p><b>He made its horns (qarnotav) on its four corners; its horns were of one piece with it (miqqshah), and he overlaid it with bronze:</b> Qernot = horns (the projections at the four top corners of the altar; from qeren = horn/power/ray). The horns are structural and symbolic: blood is applied to the horns in the atonement rituals (Lev 4:7, 8:15); fleeing criminals grasped the altar horns for sanctuary (1 Kgs 1:50-51). Miqqshah again: the horns are not attached to the altar but hammered out of the same metal structure as the altar. Bronze (n'choshet) = the outer court metal; the transition from gold (inner furnishings) to bronze (outer court) is complete.</p>",
    "3": "<p><b>He made all the utensils of the altar, the pots (sirot), the shovels (ya'im), the basins (mizraqot), the forks (mizlagot), and the fire pans (machtot). He made all its utensils of bronze:</b> The complete bronze service kit for the burnt-offering altar: sirot = cooking pots (for boiling portions); ya'im = shovels (for removing ashes); mizraqot = basins for blood (from zaraq = to sprinkle/throw; the same verb as Moses throwing covenant blood on the people in 24:8); mizlagot = flesh-hooks/forks (for handling the sacrificial portions); machtot = fire-pans (for carrying coals). Every piece of hardware is bronze — the altar's service set matches its material.</p>",
    "4": "<p><b>He made for the altar a grating (mikbar r'shet n'choshet), a network of bronze, under its ledge (karkav), extending halfway down:</b> Mikbar = a grating/lattice (from a root meaning to make holes); r'shet = network/mesh; the bronze grating sits halfway down the altar, providing a shelf for the sacrifice and allowing air flow for combustion. Karkav = ledge/projection (a technical architectural term for a horizontal projection in a wall or structure). The grating's position halfway down the hollow altar creates a functional firebox — the bronze mesh holds the sacrifice while flames burn below.</p>",
    "5": "<p><b>He cast four rings on the four corners of the bronze grating as holders for the poles:</b> The grating itself has four rings for poles — an inner carrying system for the grating inside the altar. Or the four rings are at the altar's corners at the grating level, serving as the carrying rings for the entire altar via poles inserted through the grating. The precise mechanics of assembly are described so that any future Levitical generation can reconstruct the altar correctly.</p>",
    "6": "<p><b>He made the poles of acacia wood and overlaid them with bronze:</b> The altar poles follow the standard protocol: acacia wood + metal overlay. But the overlay here is bronze (not gold or silver) — the altar's poles match the altar's metal. The gradation of materials is maintained even for transport accessories.</p>",
    "7": "<p><b>And he put the poles through the rings on the sides of the altar to carry it with them. He made it hollow, with boards (n'vuv luchot asah oto):</b> N'vuv = hollow (from navav = to hollow out/bore); luchot = boards/planks; the altar is hollow — not a solid block of acacia but a box made of boards, overlaid with bronze. The hollow construction serves two purposes: portability (solid acacia + bronze would be immovably heavy) and function (the hollow interior is filled with earth or stones at each campsite per 20:24-25, creating the sacrificial fire base on fresh ground).</p>",
    "8": "<p><b>He made the basin (kiyyor) of bronze and its stand (kano) of bronze, from the mirrors (mar'ot) of the ministering women who ministered (tzov'ot asher tzav'u) at the entrance of the tent of meeting:</b> Kiyyor = basin/laver (used for washing); kano = its stand/pedestal. <b>Mar'ot</b> = mirrors (polished bronze mirrors — ancient mirrors were not glass but highly polished bronze or copper, which the women gave up for the laver); <b>tzov'ot asher tzav'u</b> = the ministering women who served (the same root tzava twice — they are army women, those who served in organized corps). These women appear nowhere else in the Pentateuch; they give up their personal mirrors — instruments of vanity and beauty — to make the vessel of priestly purification. The material transformation (beauty instrument → cleansing vessel) is itself a theological symbol: what was used for self-presentation becomes the means of purification for approach to God.</p>",
    "9": "<p><b>He made the court (chatzer). For the south side the hangings of the court were of fine twined linen (shesh moshzar), a hundred cubits:</b> Chatzer = court/enclosure (also the word for a village or unwalled settlement — a defined but open space). The court is the outermost sacred space, accessible to lay Israelites who are not priests. The court hangings are fine linen but not the colored, embroidered linen of the interior — the court maintains holiness but not the same degree as the tabernacle itself. A hundred cubits = approximately 150 feet — the full length of the southern boundary.</p>",
    "10": "<p><b>Their twenty pillars and twenty bases were of bronze, but the hooks of the pillars and their fillets were of silver:</b> The court pillars rest on bronze bases (the outer material) but their connecting hardware (hooks and fillets) is silver — the court is a transition zone between the fully bronze outer world and the silver-based inner structure. The material gradient: outside world (no metal) → court (bronze bases, silver hardware) → tabernacle walls (silver bases) → inner furnishings (gold).</p>",
    "11": "<p><b>For the north side there were hangings of a hundred cubits, their twenty pillars, twenty bases of bronze, with hooks and fillets of silver:</b> The north wall mirrors the south wall exactly: same hanging length, same pillar count, same base material, same hardware material. The court's north and south walls are symmetrical — bilateral order in the sacred space.</p>",
    "12": "<p><b>For the west side there were hangings of fifty cubits, their ten pillars, and ten bases, with hooks and fillets of silver:</b> The west end of the court: fifty cubits wide (the court is half as wide as it is long — 100 cubits by 50 cubits in total). Ten pillars at fifty cubits = five cubits per pillar spacing, consistent with the east and north/south spacing.</p>",
    "13": "<p><b>For the front to the east, fifty cubits.</b> The court entrance faces east — the direction of sunrise, the direction from which the camp approaches. The east end is fifty cubits wide (the same as the west), divided into two screen panels flanking the entrance gate.</p>",
    "14": "<p><b>The hangings for one side of the gate were fifteen cubits, with their three pillars and three bases:</b> The gate section: the overall fifty-cubit east end is divided as follows: 15 cubits of screen (south of the gate) + 20 cubits of gate opening + 15 cubits of screen (north of the gate) = 50 cubits. The gate opening (20 cubits wide) is the widest single opening in the tabernacle complex — welcoming, accessible, the point of entry for the whole congregation.</p>",
    "15": "<p><b>And so for the other side. On both sides of the gate of the court were hangings of fifteen cubits, with their three pillars and three bases:</b> The symmetry of the gate flanks: 15 cubits + 3 pillars on each side. The gate is framed, not fenced off — its design creates a portal of invitation, not a barrier. The screen of the gate (masach sha'ar hechatzer) is the first of three thresholds: court gate → tabernacle entrance → inner veil.</p>",
    "16": "<p><b>All the hangings around the court were of fine twined linen:</b> Despite using only one color and lacking the cherubim motif of the inner curtains, the court hangings are fine linen throughout — the entire court space is marked as sacred. Even the most accessible zone of the tabernacle complex uses premium material.</p>",
    "17": "<p><b>The bases for the pillars were of bronze, the hooks of the pillars and their fillets were of silver, and the overlaying of their capitals was of silver, and all the pillars of the court were filleted with silver:</b> The systematic description of the court pillar hardware: bronze bases, silver hooks and bands, silver-overlaid capitals. The silver binding of all court pillars creates a visual cohesion — all the court pillars gleam with silver bands, visually unifying the sacred space.</p>",
    "18": "<p><b>The screen for the gate of the court was embroidered with needlework in blue and purple and scarlet yarns and fine twined linen (roqem):</b> The entrance gate screen is the most elaborate element of the court — embroidered with all four colors (blue, purple, scarlet, linen), using the roqem technique. The gate is the most decorated element of the court, befitting its role as the threshold of transition from the profane world to the sacred space.</p>",
    "19": "<p><b>It was twenty cubits long and five cubits high in its breadth, corresponding to the hangings of the court:</b> The gate screen is twenty cubits wide and five cubits high — the full width of the entrance opening and the height of the court walls. The gate screen fills the entire entrance portal.</p>",
    "20": "<p><b>And their four pillars and their four bases were of bronze; their hooks were of silver, and the overlaying of their capitals and their fillets were of silver:</b> The gate screen's four pillars follow the court pattern: bronze bases, silver hardware. The gate's four pillars (vs. three for each flanking panel) mark the entrance as architecturally distinct — four is the number of completeness at the corners of a portal.</p>",
    "21": "<p><b>All the pegs (yetedot) for the tabernacle and for the court all around were of bronze:</b> Yetedot = pegs/stakes (tent pegs that anchor the guy-ropes of the tabernacle and court hangings); the pegs are all bronze — the outermost attachment point of the structure uses the court material. The hierarchy bottoms out at bronze for the ground-level anchors.</p>",
    "22": "<p><b>These are the recorded accounts (p'quddei) of the tabernacle, the tabernacle of the testimony (mishkan ha'edut):</b> Paquddei = the records/accounts/accounts (from paqad = to number/register/visit/oversee); the same root as the census (p'qudim = the numbered). Mishkan ha'edut = tabernacle of the testimony/covenant (edut = testimony, referring to the tablets of the testimony in the ark). The tabernacle is defined by what it houses: the testimony, the covenant record.</p>",
    "23": "<p><b>As Moses commanded, according to the service of the Levites, under the direction of Ithamar the son of Aaron the priest:</b> Ithamar (the fourth son of Aaron) has supervisory responsibility for the tabernacle accounts — an early indication of his administrative role. The Levitical service (avodah) framework for tabernacle maintenance is established here; Numbers 4 will specify each Levitical clan's transport duties in detail.</p>",
    "24": "<p><b>Bezalel the son of Uri, son of Hur, of the tribe of Judah, made all that YHWH commanded Moses:</b> The formal credit line: Bezalel is identified by father (Uri), grandfather (Hur), and tribe (Judah). Hur is the companion of Aaron at Rephidim who held Moses's arms during the battle (17:12); he may be Miriam's son. The Judah-tribe identification matters for later tradition: the artisan who built the divine dwelling is from the royal tribe.</p>",
    "25": "<p><b>And with him was Oholiab the son of Ahisamach, of the tribe of Dan, a craftsman and designer and embroiderer in blue and purple and scarlet yarns and fine twined linen:</b> Oholiab (Oholi-av = 'my father is my tent' or 'tent of the father') is from Dan — the northernmost tribe. The pairing of Bezalel (Judah, south) and Oholiab (Dan, north) represents the full geographic and tribal breadth of Israel contributing to the tabernacle construction. Together they represent the whole people.</p>",
    "26": "<p><b>All the gold that was used for the work, in all the construction of the sanctuary, the gold from the offering, was twenty-nine talents and seven hundred and thirty shekels, by the shekel of the sanctuary:</b> The gold inventory: 29 talents + 730 shekels. A talent = approximately 75 pounds = approximately 34 kg; so approximately 2,175 pounds = nearly a ton of gold in the entire tabernacle. The accounting is exact: the gold total is tallied to the shekel (the shekel of the sanctuary = a standard weight kept at the tabernacle to prevent fraud — the sanctuary maintained the reference standard for commerce).</p>",
    "27": "<p><b>The silver from those of the congregation who were numbered was a hundred talents and 1,775 shekels, by the shekel of the sanctuary:</b> The silver total of 100 talents + 1,775 shekels came entirely from the census half-shekels (v.26 = the ransom of those numbered). One hundred talents = 100 silver bases for the tabernacle frames and inner veil pillars; 1,775 shekels = the hooks, fillets, and overlays for the court pillars. Every ounce of structural silver in the tabernacle represents a numbered Israelite — the tabernacle's foundations literally consist of the registered lives of the people of God.</p>",
    "28": "<p><b>He made the hooks of the pillars and overlaid their capitals and filleted them with it:</b> The 1,775 remaining shekels of silver (after making the 100 bases) went entirely to the court pillar hardware: the hooks, the capital overlays, and the connecting fillets. Nothing was wasted; the census surplus accounts were precisely expended.</p>",
    "29": "<p><b>The bronze of the offering was seventy talents and 2,400 shekels:</b> The bronze total: 70 talents + 2,400 shekels — contributed as a freewill offering (not from the census; the census silver was the ransom payment). Bronze was contributed voluntarily; silver was a required payment. The material hierarchy corresponds to the spiritual hierarchy: gold (most valuable, inner furnishings), silver (census-ransom, structural foundations), bronze (freewill, outer court and practical implements).</p>",
    "30": "<p><b>With it he made the bases for the entrance of the tent of meeting, the bronze altar and the bronze grating for it, and all the utensils of the altar:</b> The complete inventory of what bronze was used for: the entrance bases (5 for the entrance screen pillars), the altar and its grating, and all the altar's service utensils. The bronze goes first and primarily to the sacrificial apparatus — the altar, its tools, its support structure.</p>",
    "31": "<p><b>The bases of the court all around, and the bases of the gate of the court, and all the pegs of the tabernacle, and all the pegs of the court all around:</b> The final bronze allocation: all the court bases (56 bases for the 56 court pillars), the gate screen bases (4), and every tent peg throughout the entire complex. The pegs (yetedot) that literally hold the tabernacle to the ground are bronze — the material that connects the holy structure to the earth is the most utilitarian metal, the one farthest from gold.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'exodus')
    merge_comm(existing, EXODUS_ORIGINAL)
    save_comm('mkt-original', 'exodus', existing)
    print('Exodus 36-38 mkt-original commentary written.')

if __name__ == '__main__':
    main()
